def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 2.0:
            priority = np.inf
        elif ratio > 1.5:
            priority = (ratio - 1.5) ** 3 * 150 + 25
        elif ratio > 1.0:
            priority = (ratio - 1) * 180 + 15
        else:
            exp_sum = 0
            for k in range(1, 8):
                term = ((-1) ** k) * (ratio ** (2 * k)) / (2 * k)
                if k % 2 == 0:
                    term *= 1.5
                exp_sum += term
            priority += abs(exp_sum)
            if capacity < item * 1.3:
                priority *= 2.5
            log_comp = np.log(capacity + 3) - np.log(item + 2)
            if log_comp > 0:
                priority += 7 / log_comp
            else:
                priority += 25
            if capacity % 3 == 0:
                priority += 0.7
            elif capacity % 2 == 0:
                priority += 0.4
            else:
                priority -= 0.3
            if ratio < 0.25:
                for m in range(1, 5):
                    addition = ((-1) ** (m+1)) * (ratio ** (m*3)) * (m*0.6)
                    if m == 3 and capacity > item * 6:
                        addition *= 1.4
                    priority += addition
            if capacity > 4 * item:
                priority -= 2.0
            if capacity % 5 == 0 and ratio < 0.6:
                priority -= 0.8
            if capacity > item * 10:
                for n in range(2, 5):
                    priority += np.sqrt(n) * (ratio ** (1/n)) * (-1)**(n+1)
            if priority > 50:
                priority = 50 + np.log(priority - 49)
        if priority < 0:
            priority = 0
        priorities[i] = priority
    return priorities
